CREATE VIEW analytics.vw_juros_medio_por_classificacao AS
 SELECT p.classificacao_emprestimo,
    round(avg(f.juros_aplicado), 3) AS juros_medio_aplicado
   FROM (analytics.fato_emprestimo f
     JOIN analytics.dim_perfil_emprestimo p ON ((p.id_perfil_emprestimo = f.id_perfil_emprestimo)))
  GROUP BY p.classificacao_emprestimo
  ORDER BY (round(avg(f.juros_aplicado), 3)) DESC;


ALTER VIEW analytics.vw_juros_medio_por_classificacao OWNER TO postgres;

--
-- TOC entry 230 (class 1259 OID 16455)
-- Name: vw_taxa_inadimplencia_por_finalidade; Type: VIEW; Schema: analytics; Owner: postgres
--

CREATE VIEW analytics.vw_taxa_inadimplencia_por_finalidade AS
 SELECT p.finalidade_emprestimo,
    round((100.0 * avg(f.status_emprestimo)), 2) AS taxa_inadimplencia_pct
   FROM (analytics.fato_emprestimo f
     JOIN analytics.dim_perfil_emprestimo p ON ((p.id_perfil_emprestimo = f.id_perfil_emprestimo)))
  GROUP BY p.finalidade_emprestimo
  ORDER BY (round((100.0 * avg(f.status_emprestimo)), 2)) DESC;


ALTER VIEW analytics.vw_taxa_inadimplencia_por_finalidade OWNER TO postgres;

